const trigger = $('Trigger sub-workflow auditoria').first().json;
const fechaHora = new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });

const texto = [
  '⚠️ Error en sistema CatalogBot',
  '',
  'No se pudo registrar una operación en el historial de auditoría.',
  '',
  `Acción: ${trigger.accion || 'desconocida'}`,
  `Producto: ${trigger.producto_nombre || trigger.producto_id || 'N/A'}`,
  `Usuario: ${trigger.usuario_nombre || trigger.telefono || 'N/A'}`,
  `Hora: ${fechaHora}`,
  '',
  'El cambio SÍ se aplicó en el ecommerce, pero no quedó registrado en el historial. Revisar logs de n8n.'
].join('\n');

return [{
  json: {
    schema: trigger.schema,
    whatsapp_instance: trigger.whatsapp_instance,
    cliente_id: trigger.cliente_id,
    texto_alerta: texto
  }
}];

const alertaData = $('Preparar mensaje de alerta para admin').first().json;
const adminData = $input.first().json;

return [{
  json: {
    schema: alertaData.schema,
    whatsapp_instance: alertaData.whatsapp_instance,
    admin_telefono: adminData.telefono || null,
    texto_alerta: alertaData.texto_alerta
  }
}];

const errorData = $input.first().json;
return [{
  json: {
    workflow: 'WF-D_auditoria',
    nodo: errorData.execution?.lastNodeExecuted || 'desconocido',
    error_tipo: 'ERROR_CRITICO_AUDITORIA',
    error_detalle: errorData.error?.message || JSON.stringify(errorData.error || {})
  }
}];
